  ('aboriginal-6f0ba476-moex-00700', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '關於次佳理論之敘述，下列何者正確？', '["在次佳的情況下，若有可以移除的扭曲，未必要將之移除", "次佳理論所探討的經濟體系是所有符合伯瑞圖效率的條件都可以達成", "根據次佳理論，只對勞動所得課稅，必定比對勞動所得、商品和儲蓄都課稅好", "若一政策只有對消費造成扭曲，必定比另一政策造成消費和生產都扭曲好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00701', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '有關雷姆斯法則（Ramseyrule）之敘述，下列何者正確？', '["最適條件為所有財貨課徵相同稅率", "最適條件為課稅商品稅率高低和價格需求彈性絕對值成正比", "最適租稅必須使得所有財貨課稅後價格下降的比例一樣", "最適商品稅稅率的設計應使課稅後所有財貨的受補償需求量減少相同的比例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00702', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '拉法曲線（Laffercurve）說明稅率與稅收之間存在何種變化關係？', '["隨著稅率的增加，稅收會呈現先增加而後減少的情形", "無論稅率高低，提高稅率會使稅收增加", "無論稅率高低，提高稅率會使稅收降低", "隨著稅率的增加，稅收會呈現先減少而後增加的情形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00703', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '考慮下圖的兩期生命循環週期模型，消費者第0期所得（Y ）為$200，第1期所得（Y ）為$150，', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00704', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '1 消費者最適選擇為C、C 。假設消費者可在現行市場利率0.2下自由借貸，BD為預算線。下列', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 0, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00705', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '1 何者正確？ 1期消費 E 0 0期消費', '["B點為$390，在第0期借款", "B點為$390，在第0期儲蓄", "B點為$350，在第0期借款", "B點為$350，在第0期儲蓄"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 0, "answer_corrected": false, "flags": ["answer_missing"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00706', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '承上題，如果政府對利息所得課稅且利息費用可列為扣除額，則上圖中預算線的改變為何？', '["因為利率沒有變動，所以課稅後預算線也不會改變", "課稅後預算線比上圖預算線陡，因為每減少1元第0期消費可以換到的第1期消費數量增加", "課稅後預算線比上圖預算線陡，因為每減少1元第0期消費可以換到的第1期消費數量減少", "課稅後預算線比上圖預算線平坦，因為每減少1元第0期消費可以換到的第1期消費數量減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00707', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '何謂稅式支出？', '["政府為達成特定政策目的，透過租稅的減免或優惠，所減少的稅收", "政府為達成特定政策目的，透過加稅的方式，所增加的稅收", "政府為達成特定政策目的，對特定的個人或團體，所給與的現金補貼", "政府為達成特定政策目的，透過加稅的方式，所增加的行政成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00708', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '甲原來捐贈某一金額，捐贈為正常財，捐贈可列為扣除額後，甲的捐贈行為如何改變？', '["替代效果會使得捐贈增加，而所得效果會使得捐贈減少", "替代效果會使得捐贈減少，而所得效果會使得捐贈增加", "替代效果及所得效果都會使得捐贈增加", "替代效果及所得效果都會使得捐贈減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00709', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '稅法的制訂在選擇以個人或家庭為計稅單位時，下列何者不為考量因素？', '["有相同所得的家庭在其他條件相同下，應支付相同的租稅", "在其他條件不變下，夫妻兩人婚後租稅負擔總和應和婚前相同", "邊際稅率遞增", "邊際稅率不變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
